{
  "semantic_mode": "stable",
  "lean": "def is_sorted {α : Type} [preorder α] : list α → Prop := sorted (≤)",
  "assumptions": [
    "α is a type",
    "[preorder α] is a preorder on α"
  ],
  "preconditions": [
    "input list is of type α"
  ],
  "postconditions": [
    "output list is a permutation of the input list",
    "output list is sorted in non-decreasing order"
  ],
  "invariants": [
    "stability: the relative order of equal elements is preserved",
    "permutation preservation: the output is a permutation of the input"
  ],
  "examples": [
    "[3, 1, 2] → [1, 2, 3]",
    "[5, 5, 2, 1] → [1, 2, 5, 5]"
  ],
  "notes": [
    "This specification ensures that the sorting algorithm maintains the relative order of equal elements and produces a sorted permutation of the input list."
  ]
}

{
  "semantic_mode": "refill_first",
  "lean": "theorem token_bucket_refill_first { ... }",
  "assumptions": [
    "Token bucket with capacity C and refill rate R",
    "Refill and consume operations are atomic"
  ],
  "preconditions": [
    "Token bucket initialized with tokens less than or equal to capacity C"
  ],
  "postconditions": [
    "Tokens are refilled before any consume operation at the same timestamp"
  ],
  "invariants": [
    "Number of tokens in the bucket is always between 0 and C"
  ],
  "examples": [
    "Initial tokens: 5, Capacity: 10, Refill rate: 2, Consume 3 tokens -> Tokens: 4",
    "Initial tokens: 8, Capacity: 10, Refill rate: 3, Consume 2 tokens -> Tokens: 9"
  ],
  "notes": [
    "Ensures that tokens are available for consumption immediately after refill"
  ]
}

