{
  "semantic_mode": "exclusive",
  "lean": "theorem token_expiry_exclusive (t : Time) (expiry : Time) : ¬ valid_at t expiry ↔ t ≥ expiry",
  "assumptions": [
    "Time is a totally ordered set",
    "valid_at t expiry checks if token is valid at time t"
  ],
  "preconditions": [
    "t and expiry are valid time instances"
  ],
  "postconditions": [
    "Token is invalid at time t if t is equal to or greater than expiry"
  ],
  "invariants": [
    "Token validity is checked only at discrete time points"
  ],
  "examples": [
    {
      "t": "2023-10-01T12:00:00",
      "expiry": "2023-10-01T12:00:00",
      "valid": false
    },
    {
      "t": "2023-10-01T11:59:59",
      "expiry": "2023-10-01T12:00:00",
      "valid": true
    }
  ],
  "notes": [
    "Exclusive semantics mean the token is invalid at the exact expiry time."
  ]
}
```

{
  "semantic_mode": "inclusive",
  "lean": "def token_valid_at_expiry (token : Token) : Prop := token.expiry ≤ current_time",
  "assumptions": [
    "token: the token to be validated",
    "current_time: the current timestamp"
  ],
  "preconditions": [
    "token must have a defined expiry timestamp",
    "current_time must be defined"
  ],
  "postconditions": [
    "returns true if the token is valid at the exact expiry timestamp"
  ],
  "invariants": [
    "the token expiry timestamp remains constant during validation"
  ],
  "examples": [
    "token: {expiry: 100}, current_time: 100 => returns true",
    "token: {expiry: 100}, current_time: 101 => returns false"
  ],
  "notes": [
    "This specification assumes that the token is considered valid at the exact moment of expiry."
  ]
}

{
  "semantic_mode": "inclusive",
  "lean": "def validTokenAtExpiry (token : Token) : Prop := token.isValid && token.expiryTime <= currentTime",
  "assumptions": [
    "currentTime is the current time when the validation is performed",
    "Token is a data structure representing a token with fields isValid and expiryTime"
  ],
  "preconditions": [
    "token.isValid == true"
  ],
  "postconditions": [
    "Returns true if the token is valid exactly at the expiry timestamp"
  ],
  "invariants": [
    "The token remains valid until the expiry time inclusive"
  ],
  "examples": [
    "Example 1: Token expiry at 10:00:00, currentTime is 10:00:00, token.isValid = true -> validTokenAtExpiry(token) = true",
    "Example 2: Token expiry at 10:00:00, currentTime is 10:00:01, token.isValid = true -> validTokenAtExpiry(token) = false"
  ],
  "notes": [
    "This specification considers the token to be valid at the exact expiry time"
  ]
}

{
  "semantic_mode": "inclusive",
  "lean": "def token_valid_at_expiry (token : Token) : Prop := token.expiry <= current_time",
  "assumptions": [
    "token: the token being validated",
    "current_time: the current time when validation is performed"
  ],
  "preconditions": [
    "token must have a defined expiry timestamp",
    "current_time must be defined"
  ],
  "postconditions": [
    "the token is considered valid at its expiry timestamp if the expiry time is less than or equal to the current time"
  ],
  "invariants": [
    "the validity of the token at expiry is determined solely by the comparison with the current time"
  ],
  "examples": [
    "Token expiry: 10:00:00, Current time: 10:00:00 -> Valid",
    "Token expiry: 10:00:00, Current time: 10:00:01 -> Invalid"
  ],
  "notes": [
    "This specification considers the token to be valid at the exact moment of its expiry",
    "The comparison is inclusive to ensure that the token is considered valid until the expiry instant"
  ]
}

